const library = $('Read Flow Library').all();
const audits = $('Read Flow Audits').all();

const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Count flows added this week
const newFlows = library.filter(item => {
  const added = new Date(item.json.fields['Date Added']);
  return added >= weekAgo;
});

const captured = newFlows.filter(i => i.json.fields.Source === 'Captured').length;
const adapted = newFlows.filter(i => i.json.fields.Source === 'Adapted').length;
const templated = newFlows.filter(i => i.json.fields.Source === 'Template').length;

// Count audits this week
const newAudits = audits.filter(item => {
  const date = new Date(item.json.fields['Audit Date']);
  return date >= weekAgo;
});

// Platform breakdown
const platforms = {};
library.forEach(item => {
  const p = item.json.fields.Platform || 'Unknown';
  platforms[p] = (platforms[p] || 0) + 1;
});

const platformStr = Object.entries(platforms)
  .sort((a, b) => b[1] - a[1])
  .map(([k, v]) => `${k}: ${v}`)
  .join(', ');

const summary = `FLOW MACHINE - WEEKLY DIGEST\n` +
  `---\n` +
  `New this week: ${newFlows.length} flows\n` +
  `  Captured: ${captured}\n` +
  `  Adapted: ${adapted}\n` +
  `  Templates: ${templated}\n` +
  `Audits run: ${newAudits.length}\n` +
  `---\n` +
  `Library total: ${library.length} flows\n` +
  `Platforms: ${platformStr}\n` +
  `---`;

return [{ json: { summary } }];
